-- 创建表
CREATE TABLE IF NOT EXISTS my_table (
id SERIAL PRIMARY KEY,
name VARCHAR(100),
description TEXT
);

-- 向表中插入数据
INSERT INTO my_table (name, description) VALUES
('Book1', 'This is a book about SQL.'),
('Book2', 'Learn SQL the easy way.'),
('Book3', 'Advanced SQL techniques.');

-- 调用存储过程
SELECT * FROM example_procedure('SQL');
-- 获取输出参数的值
SELECT total_count, matched_count FROM example_procedure('SQL');
